CREATE TABLE public."PitData" (id bigint GENERATED BY DEFAULT AS IDENTITY NOT NULL, created_at timestamp with time zone DEFAULT now() NOT NULL, event text, scouted_by uuid DEFAULT auth.uid() NOT NULL, pit_team_number smallint NOT NULL, pit_drivetrain text, pit_weight real NOT NULL, pit_language text NOT NULL, pit_vibe_check smallint NOT NULL, pit_comments text);
ALTER TABLE public."PitData" ENABLE ROW LEVEL SECURITY;
ALTER TABLE public."PitData" ADD CONSTRAINT "PitData_pkey" PRIMARY KEY (id);
ALTER TABLE public."PitData" ADD CONSTRAINT "PitData_scouted_by_fkey" FOREIGN KEY (scouted_by) REFERENCES public."User"(user_id);
ALTER TABLE public."PitData" ADD CONSTRAINT "PitData_vibe_check_check" CHECK (pit_vibe_check >= 1 AND pit_vibe_check <= 5);
GRANT ALL ON public."PitData" TO anon;
GRANT ALL ON public."PitData" TO authenticated;
GRANT ALL ON public."PitData" TO service_role;
CREATE POLICY "Enable insert for authenticated users only" ON public."PitData" FOR INSERT TO authenticated WITH CHECK ((scouted_by = auth.uid()));
CREATE POLICY "Enable read access for logged in users" ON public."PitData" FOR SELECT TO authenticated USING (true);
CREATE POLICY "Enable update for authenticated users only" ON public."PitData" FOR UPDATE TO authenticated USING (true);
